class Solution:
    def sumOfPowers(self, nums, k):
        MOD = 10**9 + 7
        from itertools import combinations
        total = 0
        for combo in combinations(nums, k):
            s = sorted(combo)
            power = min(s[i+1]-s[i] for i in range(len(s)-1))
            total = (total + power) % MOD
        return total

