class Solution:
    def sumOfPowers(self, nums, k):
        MOD = 10**9 + 7
        nums = sorted(nums)
        n = len(nums)
        from functools import lru_cache
        INF = float('inf')

        @lru_cache(maxsize=None)
        def dp(i, rem, prev, min_gap):
            if rem == 0:
                return min_gap % MOD
            if i == n:
                return 0
            # skip nums[i]
            res = dp(i + 1, rem, prev, min_gap)
            # take nums[i]
            gap = nums[i] - nums[prev] if prev >= 0 else INF
            new_min = min(min_gap, gap)
            res = (res + dp(i + 1, rem - 1, i, new_min)) % MOD
            return res

        return dp(0, k, -1, INF)

