var sumOfPowers = function(nums, k) {
    const MOD = 1000000007n;
    nums = [...nums].sort((a, b) => a - b);
    const n = nums.length;
    const INF = BigInt(2e15);
    const memo = new Map();

    function dp(i, rem, prev, minGap) {
        if (rem === 0) return minGap % MOD;
        if (i === n) return 0n;
        const key = `${i},${rem},${prev},${minGap}`;
        if (memo.has(key)) return memo.get(key);
        // skip
        let res = dp(i + 1, rem, prev, minGap);
        // take
        const gap = prev < 0 ? INF : BigInt(nums[i] - nums[prev]);
        const newMin = minGap < gap ? minGap : gap;
        res = (res + dp(i + 1, rem - 1, i, newMin)) % MOD;
        memo.set(key, res);
        return res;
    }

    return Number(dp(0, k, -1, INF));
};
